-- Insert 50 coordination exercises
INSERT INTO coaching.exercise (
  facility_id, name, slug, description, sport_id, skill_level, age_min,
  default_sets, default_reps, default_work_seconds, default_rest_seconds, est_seconds_per_set,
  is_published, visibility,
  card_summary, coach_language, athlete_language,
  movement_family, primary_phase_key, phase_subrole, primary_order_slot,
  movement_requirements, coaching_execution
)
SELECT
  f.id,
  d.name, d.slug, d.description,
  (SELECT id FROM coaching.sport WHERE key = 'fitness'),
  d.skill::public.skill_level,
  d.age_min,
  d.sets, d.reps, d.work, d.rest, d.est,
  TRUE, 'facility',
  d.summary, d.coach_lang, d.athlete_lang,
  d.family, d.phase_key, d.subrole, d.slot,
  d.req::jsonb, d.exec::jsonb
FROM (VALUES
  ('Color-Call Tennis Ball Catch on Single-Leg Balance', 'color-call-tennis-ball-catch-on-single-leg-balance', 'Athlete balances on one leg while catching the correct colored tennis ball after a late coach call. The goal is not random difficulty; it is coordinated seeing, deciding, moving, catching, and resetting with repeatable mechanics.', 'BEGINNER', 8, 2, 5, 30, 45, 75, 'Athlete balances on one leg while catching the correct colored tennis ball after a late coach call.', 'Primary subrole: Balance, Coordination, and Rhythm. Coach this as a coordination drill first: accurate perception, organized feet, clean catch, and controlled reset before more speed or pressure.', 'Catch the called color.', 'Visual Tracking + Catching Decision', 'movement_intelligence', 'balance_coordination_rhythm', 'single_leg_color_catch', '{"primary_joint_actions":["multi_directional_locomotion","hip_knee_ankle_coordination","visual_tracking","hand_eye_coordination"],"primary_tissues":["intrinsic_foot","calves","glutes","hip_stabilizers","anterior_core","shoulder_stabilizers","forearm_hand_complex"],"primary_motor_control_demands":["visual_tracking","choice_reaction","interlimb_timing","catch_timing"],"postural_shape":null,"breathing_demand":"controlled_rhythm","balance_demand":"high_reactive","coordination_demand":"multi_stimulus_reactive","impact_level":1}'::jsonb, '{"movement_description":"Athlete balances on one leg while catching the correct colored tennis ball after a late coach call. The goal is not random difficulty; it is coordinated seeing, deciding, moving, catching, and resetting with repeatable mechanics.","setup":["Set a safe lane or station with clear boundaries and no collision risk.","Choose one primary cue before the set: color, number, direction, partner movement, or ball flight.","Start at a speed where the athlete can see the cue, move cleanly, and catch without panic."],"execution_steps":["Athlete starts in the prescribed stance or movement pattern.","Coach or partner gives the cue late enough to require attention but early enough to keep the rep safe.","Athlete solves the cue, tracks the object, catches or handles the ball, and finishes in control.","Athlete calls what they saw after the catch, then resets before the next attempt."],"coach_cues":["Catch the called color.","Eyes quiet before hands quick.","Solve the cue first.","Catch clean, then reset.","Stop before sloppy."],"common_faults":["Looking at the feet instead of the cue or ball.","Rushing the rep and guessing before the stimulus is clear.","Adding extra steps, hops, or body sway after the catch.","Catching with panic hands instead of soft hands and a stable finish.","Turning the drill into fatigue work instead of coordination practice."]}'::jsonb),
  ('Single-Leg Football Catch with Late Color Call', 'single-leg-football-catch-with-late-color-call', 'Single-leg football catch where the athlete must identify a color or cone call before securing the ball. The goal is not random difficulty; it is coordinated seeing, deciding, moving, catching, and resetting with repeatable mechanics.', 'BEGINNER', 8, 2, 5, 30, 45, 75, 'Single-leg football catch where the athlete must identify a color or cone call before securing the ball.', 'Primary subrole: Balance, Coordination, and Rhythm. Coach this as a coordination drill first: accurate perception, organized feet, clean catch, and controlled reset before more speed or pressure.', 'Balance, call, catch.', 'Visual Tracking + Catching Decision', 'movement_intelligence', 'balance_coordination_rhythm', 'single_leg_late_call_football_catch', '{"primary_joint_actions":["multi_directional_locomotion","hip_knee_ankle_coordination","visual_tracking","hand_eye_coordination"],"primary_tissues":["intrinsic_foot","calves","glutes","hip_stabilizers","anterior_core","shoulder_stabilizers","forearm_hand_complex"],"primary_motor_control_demands":["visual_tracking","choice_reaction","interlimb_timing","catch_timing"],"postural_shape":null,"breathing_demand":"controlled_rhythm","balance_demand":"high","coordination_demand":"multi_stimulus_reactive","impact_level":1}'::jsonb, '{"movement_description":"Single-leg football catch where the athlete must identify a color or cone call before securing the ball. The goal is not random difficulty; it is coordinated seeing, deciding, moving, catching, and resetting with repeatable mechanics.","setup":["Set a safe lane or station with clear boundaries and no collision risk.","Choose one primary cue before the set: color, number, direction, partner movement, or ball flight.","Start at a speed where the athlete can see the cue, move cleanly, and catch without panic."],"execution_steps":["Athlete starts in the prescribed stance or movement pattern.","Coach or partner gives the cue late enough to require attention but early enough to keep the rep safe.","Athlete solves the cue, tracks the object, catches or handles the ball, and finishes in control.","Athlete calls what they saw after the catch, then resets before the next attempt."],"coach_cues":["Balance, call, catch.","Eyes quiet before hands quick.","Solve the cue first.","Catch clean, then reset.","Stop before sloppy."],"common_faults":["Looking at the feet instead of the cue or ball.","Rushing the rep and guessing before the stimulus is clear.","Adding extra steps, hops, or body sway after the catch.","Catching with panic hands instead of soft hands and a stable finish.","Turning the drill into fatigue work instead of coordination practice."]}'::jsonb),
  ('Jog-Cut-Catch-Scan Drill', 'jog-cut-catch-scan-drill', 'Athlete jogs, cuts on command, catches, then immediately scans and calls a second target. The goal is not random difficulty; it is coordinated seeing, deciding, moving, catching, and resetting with repeatable mechanics.', 'INTERMEDIATE', 8, 2, 5, 30, 45, 75, 'Athlete jogs, cuts on command, catches, then immediately scans and calls a second target.', 'Primary subrole: Perception-Action Reactive Movement. Coach this as a coordination drill first: accurate perception, organized feet, clean catch, and controlled reset before more speed or pressure.', 'Cut, catch, scan.', 'Visual Tracking + Catching Decision', 'movement_intelligence', 'perception_action_reactive_movement', 'jog_cut_catch_scan', '{"primary_joint_actions":["multi_directional_locomotion","hip_knee_ankle_coordination","trunk_rotation_control","hip_rotation","visual_tracking","hand_eye_coordination"],"primary_tissues":["intrinsic_foot","calves","glutes","hip_stabilizers","anterior_core","shoulder_stabilizers","forearm_hand_complex","quadriceps","hamstrings","achilles_tendon"],"primary_motor_control_demands":["visual_tracking","choice_reaction","interlimb_timing","catch_timing"],"postural_shape":null,"breathing_demand":"braced_exhale_on_cut_or_landing","balance_demand":"dynamic","coordination_demand":"multi_stimulus_reactive","impact_level":3}'::jsonb, '{"movement_description":"Athlete jogs, cuts on command, catches, then immediately scans and calls a second target. The goal is not random difficulty; it is coordinated seeing, deciding, moving, catching, and resetting with repeatable mechanics.","setup":["Set a safe lane or station with clear boundaries and no collision risk.","Choose one primary cue before the set: color, number, direction, partner movement, or ball flight.","Start at a speed where the athlete can see the cue, move cleanly, and catch without panic."],"execution_steps":["Athlete starts in the prescribed stance or movement pattern.","Coach or partner gives the cue late enough to require attention but early enough to keep the rep safe.","Athlete solves the cue, tracks the object, catches or handles the ball, and finishes in control.","Athlete calls what they saw after the catch, then resets before the next attempt."],"coach_cues":["Cut, catch, scan.","Eyes quiet before hands quick.","Solve the cue first.","Catch clean, then reset.","Stop before sloppy."],"common_faults":["Looking at the feet instead of the cue or ball.","Rushing the rep and guessing before the stimulus is clear.","Adding extra steps, hops, or body sway after the catch.","Catching with panic hands instead of soft hands and a stable finish.","Turning the drill into fatigue work instead of coordination practice."]}'::jsonb),
  ('Two-Ball Number Call Catch', 'two-ball-number-call-catch', 'Partner tosses two numbered or colored balls and the athlete catches only the called option. The goal is not random difficulty; it is coordinated seeing, deciding, moving, catching, and resetting with repeatable mechanics.', 'BEGINNER', 8, 2, 5, 30, 45, 75, 'Partner tosses two numbered or colored balls and the athlete catches only the called option.', 'Primary subrole: Perception-Action Reactive Movement. Coach this as a coordination drill first: accurate perception, organized feet, clean catch, and controlled reset before more speed or pressure.', 'Catch the right one.', 'Visual Tracking + Catching Decision', 'movement_intelligence', 'perception_action_reactive_movement', 'two_ball_number_call_catch', '{"primary_joint_actions":["trunk_rotation_control","hip_rotation","visual_tracking","hand_eye_coordination"],"primary_tissues":["intrinsic_foot","calves","glutes","hip_stabilizers","anterior_core","shoulder_stabilizers","forearm_hand_complex"],"primary_motor_control_demands":["visual_tracking","choice_reaction","interlimb_timing","catch_timing"],"postural_shape":null,"breathing_demand":"controlled_rhythm","balance_demand":"moderate","coordination_demand":"multi_stimulus_reactive","impact_level":1}'::jsonb, '{"movement_description":"Partner tosses two numbered or colored balls and the athlete catches only the called option. The goal is not random difficulty; it is coordinated seeing, deciding, moving, catching, and resetting with repeatable mechanics.","setup":["Set a safe lane or station with clear boundaries and no collision risk.","Choose one primary cue before the set: color, number, direction, partner movement, or ball flight.","Start at a speed where the athlete can see the cue, move cleanly, and catch without panic."],"execution_steps":["Athlete starts in the prescribed stance or movement pattern.","Coach or partner gives the cue late enough to require attention but early enough to keep the rep safe.","Athlete solves the cue, tracks the object, catches or handles the ball, and finishes in control.","Athlete calls what they saw after the catch, then resets before the next attempt."],"coach_cues":["Catch the right one.","Eyes quiet before hands quick.","Solve the cue first.","Catch clean, then reset.","Stop before sloppy."],"common_faults":["Looking at the feet instead of the cue or ball.","Rushing the rep and guessing before the stimulus is clear.","Adding extra steps, hops, or body sway after the catch.","Catching with panic hands instead of soft hands and a stable finish.","Turning the drill into fatigue work instead of coordination practice."]}'::jsonb),
  ('Partner Random Bounce Catch with Balance Reset', 'partner-random-bounce-catch-with-balance-reset', 'Random bounce catches force visual tracking, quick hand choice, and a clean balance reset after each rep. The goal is not random difficulty; it is coordinated seeing, deciding, moving, catching, and resetting with repeatable mechanics.', 'BEGINNER', 8, 2, 5, 30, 45, 75, 'Random bounce catches force visual tracking, quick hand choice, and a clean balance reset after each rep.', 'Primary subrole: Perception-Action Reactive Movement. Coach this as a coordination drill first: accurate perception, organized feet, clean catch, and controlled reset before more speed or pressure.', 'Track the bounce.', 'Visual Tracking + Catching Decision', 'movement_intelligence', 'perception_action_reactive_movement', 'random_bounce_catch_balance_reset', '{"primary_joint_actions":["multi_directional_locomotion","hip_knee_ankle_coordination","visual_tracking","hand_eye_coordination"],"primary_tissues":["intrinsic_foot","calves","glutes","hip_stabilizers","anterior_core","shoulder_stabilizers","forearm_hand_complex"],"primary_motor_control_demands":["visual_tracking","choice_reaction","interlimb_timing","catch_timing"],"postural_shape":null,"breathing_demand":"controlled_rhythm","balance_demand":"dynamic","coordination_demand":"multi_stimulus_reactive","impact_level":1}'::jsonb, '{"movement_description":"Random bounce catches force visual tracking, quick hand choice, and a clean balance reset after each rep. The goal is not random difficulty; it is coordinated seeing, deciding, moving, catching, and resetting with repeatable mechanics.","setup":["Set a safe lane or station with clear boundaries and no collision risk.","Choose one primary cue before the set: color, number, direction, partner movement, or ball flight.","Start at a speed where the athlete can see the cue, move cleanly, and catch without panic."],"execution_steps":["Athlete starts in the prescribed stance or movement pattern.","Coach or partner gives the cue late enough to require attention but early enough to keep the rep safe.","Athlete solves the cue, tracks the object, catches or handles the ball, and finishes in control.","Athlete calls what they saw after the catch, then resets before the next attempt."],"coach_cues":["Track the bounce.","Eyes quiet before hands quick.","Solve the cue first.","Catch clean, then reset.","Stop before sloppy."],"common_faults":["Looking at the feet instead of the cue or ball.","Rushing the rep and guessing before the stimulus is clear.","Adding extra steps, hops, or body sway after the catch.","Catching with panic hands instead of soft hands and a stable finish.","Turning the drill into fatigue work instead of coordination practice."]}'::jsonb),
  ('Wall Toss with Shoulder Check', 'wall-toss-with-shoulder-check', 'Athlete tosses to a wall, shoulder-checks to identify a cue, then relocates the ball and catches cleanly. The goal is not random difficulty; it is coordinated seeing, deciding, moving, catching, and resetting with repeatable mechanics.', 'BEGINNER', 8, 2, 5, 30, 45, 75, 'Athlete tosses to a wall, shoulder-checks to identify a cue, then relocates the ball and catches cleanly.', 'Primary subrole: Perception-Action Reactive Movement. Coach this as a coordination drill first: accurate perception, organized feet, clean catch, and controlled reset before more speed or pressure.', 'Check, relocate, catch.', 'Visual Tracking + Catching Decision', 'movement_intelligence', 'perception_action_reactive_movement', 'wall_toss_shoulder_check', '{"primary_joint_actions":["trunk_rotation_control","hip_rotation","visual_tracking","hand_eye_coordination"],"primary_tissues":["intrinsic_foot","calves","glutes","hip_stabilizers","anterior_core","shoulder_stabilizers","forearm_hand_complex"],"primary_motor_control_demands":["visual_tracking","choice_reaction","interlimb_timing","catch_timing"],"postural_shape":null,"breathing_demand":"controlled_rhythm","balance_demand":"moderate","coordination_demand":"multi_stimulus_reactive","impact_level":1}'::jsonb, '{"movement_description":"Athlete tosses to a wall, shoulder-checks to identify a cue, then relocates the ball and catches cleanly. The goal is not random difficulty; it is coordinated seeing, deciding, moving, catching, and resetting with repeatable mechanics.","setup":["Set a safe lane or station with clear boundaries and no collision risk.","Choose one primary cue before the set: color, number, direction, partner movement, or ball flight.","Start at a speed where the athlete can see the cue, move cleanly, and catch without panic."],"execution_steps":["Athlete starts in the prescribed stance or movement pattern.","Coach or partner gives the cue late enough to require 