  ('color-call-tennis-ball-catch-on-single-leg-balance', 1, 1, FALSE, 'optional', ARRAY['Athlete can complete the base movement pattern without pain.', 'Athlete can track and catch the selected object safely at low speed.', 'Space is clear for a recovery step, missed catch, or safe deceleration.', 'No active dizziness, concussion symptoms, or unsafe visual-tracking limitations.']::text[], ARRAY['Acute pain with the required stance, cut, hop, catch, or landing.', 'Uncontrolled balance loss that creates collision or fall risk.', 'Active concussion, vertigo, or visual symptoms without medical clearance.']::text[], ARRAY['Supported single-leg balance catch', 'Two-foot stance color catch', 'Predictable partner toss', 'Two-option color call']::text[]),
  ('single-leg-football-catch-with-late-color-call', 1, 1, FALSE, 'optional', ARRAY['Athlete can complete the base movement pattern without pain.', 'Athlete can track and catch the selected object safely at low speed.', 'Space is clear for a recovery step, missed catch, or safe deceleration.', 'No active dizziness, concussion symptoms, or unsafe visual-tracking limitations.']::text[], ARRAY['Acute pain with the required stance, cut, hop, catch, or landing.', 'Uncontrolled balance loss that creates collision or fall risk.', 'Active concussion, vertigo, or visual symptoms without medical clearance.']::text[], ARRAY['Supported single-leg balance catch', 'Two-foot stance color catch', 'Predictable partner toss', 'Two-option color call']::text[]),
